import React, { useState, useEffect } from "react";
import MapView from "../components/MapView";
import CameraCapture from "../components/CameraCapture";
import { io } from "socket.io-client";
import "./journey.css";

const socket = io("http://localhost:5000");

function Journey() {
  const [destination, setDestination] = useState("");
  const [originCoords, setOriginCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [info, setInfo] = useState(null);
  const [voiceOn, setVoiceOn] = useState(false);
  const [capturedImage, setCapturedImage] = useState(null);

  /* 📍 LIVE LOCATION */
  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const lat = pos.coords.latitude;
        const lon = pos.coords.longitude;

        const current = { lat, lng: lon };
        setOriginCoords(current);

        // send to backend
        fetch("http://localhost:5000/location", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ lat, lon }),
        });

        // socket
        socket.emit("location", { lat, lon });
      },
      (err) => console.log(err),
      { enableHighAccuracy: true }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  /* 🔍 RECEIVE DESTINATION FROM MAP SEARCH */
  useEffect(() => {
    window.setDestinationFromSearch = (coords) => {
      setDestinationCoords(coords);
    };
  }, []);

  /* 🎯 SET DESTINATION (manual fallback) */
  const setDestinationFunc = () => {
    if (!originCoords) return alert("Location not ready");

    setDestinationCoords({
      lat: originCoords.lat + 0.005,
      lng: originCoords.lng + 0.005,
    });
  };

  /* 📷 HANDLE IMAGE */
  const handleCapture = async (img) => {
    setCapturedImage(img);

    try {
      await fetch("http://localhost:5000/upload", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ image: img }),
      });

      console.log("📷 Image uploaded");
    } catch (err) {
      console.log(err);
    }
  };

  /* 🚨 SOS */
  const triggerEmergency = async () => {
    if (!originCoords) return alert("Location not available");

    try {
      await fetch("http://localhost:5000/sos", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          lat: originCoords.lat,
          lon: originCoords.lng,
          image: capturedImage,
        }),
      });

      alert("🚨 SOS Sent!");
    } catch (err) {
      console.log(err);
      alert("SOS failed");
    }
  };

  /* 🎤 VOICE SOS */
  useEffect(() => {
    if (!voiceOn) return;

    const SpeechRecognition =
      window.SpeechRecognition || window.webkitSpeechRecognition;

    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.continuous = true;

    recognition.onresult = (event) => {
      const text =
        event.results[event.results.length - 1][0].transcript.toLowerCase();

      if (text.includes("help me")) {
        triggerEmergency();
      }
    };

    recognition.start();

    return () => recognition.stop();
  }, [voiceOn]);

  return (
    <div className="app">

      {/* HEADER */}
      <div className="header-card glass">
        <h2>🛡️ Women Safety Monitor</h2>
        <p>Live Tracking & Emergency Protection</p>
      </div>

      {/* DESTINATION INPUT */}
      <div className="section-card glass">
        <input
          placeholder="Enter destination (or use search in map)"
          value={destination}
          onChange={(e) => setDestination(e.target.value)}
        />

        <button onClick={setDestinationFunc}>
          📍 Set Destination
        </button>
      </div>

      {/* CAMERA */}
      <div className="section-card glass">
        <CameraCapture onCapture={handleCapture} />
      </div>

      {/* MAP */}
      <div className="map-wrap glass">
        <MapView
          origin={originCoords}
          destination={destinationCoords}
          setInfo={setInfo}
        />
      </div>

      {/* INFO */}
      <div className="section-card glass">
        <p>🚗 Distance: {info?.distance || "--"} km</p>
        <p>⏱ Time: {info?.time || "--"} mins</p>
      </div>

      {/* SOS BUTTON */}
      <button className="sos-btn" onClick={triggerEmergency}>
        🚨 SOS EMERGENCY
      </button>

      {/* ACTIONS */}
      <div className="actions">
        <button onClick={() => window.open("tel:112")}>📞 Call 112</button>

        <button
          onClick={() =>
            originCoords &&
            window.open(
              `https://maps.google.com/?q=${originCoords.lat},${originCoords.lng}`
            )
          }
        >
          📤 Share Location
        </button>

        <button onClick={() => setVoiceOn(!voiceOn)}>
          🎤 Voice {voiceOn ? "ON" : "OFF"}
        </button>
      </div>

    </div>
  );
}

export default Journey;
